// src/pages/donor/DonatePage.jsx
import { useState } from "react";
import { useToast } from "../../context/ToastContext";
import PageHeader   from "../../components/shared/PageHeader";
import Badge        from "../../components/shared/Badge";
import { fundApi }  from "../../services/api";

const fmt = (n) => n?.toLocaleString() ?? "–";

export default function DonatePage() {
  const toast = useToast();
  const [form, setForm] = useState({ userCert: "", donorId: "", fundId: "", tokenId: "", amount: "" });
  const [funds, setFunds] = useState([]);
  const [loadingFunds, setLoadingFunds] = useState(false);
  const [donating, setDonating] = useState(false);

  const upd = (key) => (e) => setForm((prev) => ({ ...prev, [key]: e.target.value }));

  const loadFunds = async () => {
    if (!form.userCert) {
      toast("UserCert is required to load funds", "error");
      return;
    }
    setLoadingFunds(true);
    try {
      const res = await fundApi.getAll({ userCert: form.userCert });
      setFunds(res?.data || []);
    } catch (err) {
      toast(err?.response?.data?.error || err.message || "Failed to load funds", "error");
      setFunds([]);
    } finally {
      setLoadingFunds(false);
    }
  };

  const handleDonate = async () => {
    if (!form.userCert || !form.donorId || !form.fundId || !form.tokenId || !form.amount) {
      toast("UserCert, donor ID, fund ID, token ID and amount are required", "error");
      return;
    }

    setDonating(true);
    try {
      await fundApi.donate(form);
      toast(`Donation of ${form.amount} tokens submitted`, "success");
      setForm((prev) => ({ ...prev, fundId: "", tokenId: "", amount: "" }));
    } catch (err) {
      toast(err?.response?.data?.error || err.message || "Donation failed", "error");
    } finally {
      setDonating(false);
    }
  };

  return (
    <div>
      <PageHeader title="Make a Donation" desc="Support a cause by donating tokens to an open fund" />
      <div className="grid-2">
        {/* Fund selector */}
        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>Load & Select Fund</div>
          <div className="form-grid section-gap" style={{ marginBottom: 14 }}>
            <div className="form-group">
              <label>User Cert</label>
              <input value={form.userCert} onChange={upd("userCert")} placeholder="User certificate ID" />
            </div>
            <div className="form-group">
              <label>Donor ID</label>
              <input value={form.donorId} onChange={upd("donorId")} placeholder="e.g. DNR001" />
            </div>
            <div className="form-actions">
              <button className="btn btn-primary" onClick={loadFunds} disabled={loadingFunds}>
                {loadingFunds ? "Loading..." : "Load Funds"}
              </button>
            </div>
          </div>
          <div className="section-gap">
            {funds.map((f) => {
              const fundId = f.fundId || f.id;
              const raised = Number(f.raisedAmount ?? f.raised ?? 0);
              const target = Number(f.fundTarget ?? f.target ?? 0);
              const donors = Number(f.totalDonors ?? f.donors ?? 0);
              const pct = target > 0 ? Math.round((raised / target) * 100) : 0;
              return (
                <div
                  key={fundId}
                  onClick={() => setForm((prev) => ({ ...prev, fundId }))}
                  style={{ padding:14, borderRadius:"var(--radius)", border:`1px solid ${form.fundId===fundId?"rgba(212,168,67,.5)":"var(--border)"}`, background: form.fundId===fundId ? "var(--gold-glow)" : "var(--bg-surface)", cursor:"pointer", transition:"all .15s" }}
                >
                  <div style={{ display:"flex", justifyContent:"space-between", marginBottom:6, flexWrap:"wrap", gap:4 }}>
                    <span style={{ fontWeight:700, fontSize:13 }}>{f.title || f.name || fundId}</span>
                    <Badge type="teal">{fundId}</Badge>
                  </div>
                  <div style={{ fontSize:12, color:"var(--text-3)", marginBottom:8 }}>
                    {fmt(raised)} / {fmt(target)} tokens · {donors} donors
                  </div>
                  <div className="progress-track"><div className="progress-fill" style={{ width:`${pct}%` }} /></div>
                  <div style={{ fontSize:11, color:"var(--gold)", marginTop:4, fontFamily:"'DM Mono',monospace" }}>{pct}% funded</div>
                </div>
              );
            })}
            {!loadingFunds && funds.length === 0 && (
              <div style={{ fontSize: 12, color: "var(--text-3)" }}>No funds loaded. Enter UserCert and click Load Funds.</div>
            )}
          </div>
        </div>

        {/* Donation form */}
        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>Donation Details</div>
          <div className="form-grid section-gap">
            <div className="stat-card gold">
              <div className="stat-label">Your Token Balance</div>
              <div className="stat-value gold">—</div>
            </div>
            <div className="form-group">
              <label>Selected Fund</label>
              <input readOnly value={form.fundId ? funds.find((f) => (f.fundId || f.id) === form.fundId)?.title || funds.find((f) => (f.fundId || f.id) === form.fundId)?.name || "" : ""} placeholder="Select a fund from the list..." />
            </div>
            <div className="form-group">
              <label>Token ID</label>
              <input value={form.tokenId} onChange={upd("tokenId")} placeholder="e.g. token001" />
            </div>
            <div className="form-group">
              <label>Amount (Tokens)</label>
              <input value={form.amount} onChange={upd("amount")} type="number" placeholder="e.g. 100" />
            </div>
            <div className="form-actions">
              <button className="btn btn-primary full-width" style={{ justifyContent:"center" }} onClick={handleDonate} disabled={donating}>
                ♡ Donate Now
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
